import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import AuthDropdown from './AuthDropdown';

export default function Navbar({ authOpen, setAuthOpen }) {
  const [scrolled, setScrolled] = useState(false);
  const [mobileMenu, setMobileMenu] = useState(false);
  const { user, logout } = useAuth();

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  // Close mobile menu when auth opens
  useEffect(() => {
    if (authOpen) setMobileMenu(false);
  }, [authOpen]);

  const navLinks = [
    { label: 'Features', href: '#features' },
    { label: 'How it Works', href: '#howitworks' },
    { label: 'About', href: '#about' },
  ];

  return (
    // Navbar is z-50 — sits above the z-30 overlay so it stays crisp
    <nav className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
      scrolled || authOpen
        ? 'bg-white/95 backdrop-blur-md shadow-md shadow-gray-100'
        : 'bg-white'
    }`}>
      <div className="max-w-7xl mx-auto px-6 py-4 flex items-center justify-between">

        {/* Logo */}
        <Link to="/" className="flex items-center gap-2.5 group">
          <div className="w-9 h-9 bg-gradient-to-br from-primary-500 to-emerald-600 rounded-xl flex items-center justify-center shadow-md shadow-primary-500/30 group-hover:scale-105 transition-transform">
            <span className="text-white text-lg">✈</span>
          </div>
          <span className="font-display font-bold text-xl text-gray-800">
            Trip<span className="text-primary-600">Nest</span>
          </span>
        </Link>

        {/* Nav Links */}
        <div className="hidden md:flex items-center gap-8">
          {navLinks.map(({ label, href }) => (
            <a
              key={label}
              href={href}
              className="text-sm font-medium text-gray-600 hover:text-primary-600 transition-colors duration-200 relative group"
            >
              {label}
              <span className="absolute -bottom-0.5 left-0 w-0 h-0.5 bg-primary-500 group-hover:w-full transition-all duration-300 rounded-full" />
            </a>
          ))}
        </div>

        {/* Auth */}
        <div className="flex items-center gap-3">
          {user ? (
            <div className="flex items-center gap-3">
              <Link
                to="/dashboard"
                className="text-sm font-medium text-gray-700 hover:text-primary-600 transition-colors"
              >
                My Trips
              </Link>
              <div className="flex items-center gap-2 bg-primary-50 rounded-full pl-2 pr-3 py-1.5 border border-primary-100">
                <div className="w-7 h-7 bg-gradient-to-br from-primary-500 to-emerald-500 rounded-full flex items-center justify-center shadow-sm">
                  <span className="text-white text-xs font-bold">{user.name?.[0]?.toUpperCase()}</span>
                </div>
                <span className="text-sm font-medium text-gray-700">{user.name?.split(' ')[0]}</span>
              </div>
              <button
                onClick={logout}
                className="text-sm text-gray-400 hover:text-red-500 transition-colors font-medium"
              >
                Logout
              </button>
            </div>
          ) : (
            <div className="relative">
              <button
                data-register-btn
                onClick={() => setAuthOpen(!authOpen)}
                className={`px-5 py-2.5 rounded-xl text-sm font-semibold transition-all duration-200 flex items-center gap-2 shadow-md
                  ${authOpen
                    ? 'bg-primary-700 text-white shadow-primary-500/40 shadow-lg'
                    : 'bg-gradient-to-r from-primary-600 to-emerald-500 text-white hover:shadow-lg hover:shadow-primary-500/30 hover:-translate-y-0.5'
                  }`}
              >
                Register Now
                <svg
                  className={`w-4 h-4 transition-transform duration-300 ${authOpen ? 'rotate-180' : ''}`}
                  fill="none" viewBox="0 0 24 24" stroke="currentColor"
                >
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                </svg>
              </button>

              <AuthDropdown isOpen={authOpen} onClose={() => setAuthOpen(false)} />
            </div>
          )}

          {/* Mobile hamburger */}
          <button
            className="md:hidden ml-2 p-2 rounded-lg hover:bg-gray-100 transition-colors"
            onClick={() => setMobileMenu(!mobileMenu)}
          >
            <svg className="w-5 h-5 text-gray-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              {mobileMenu
                ? <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                : <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
              }
            </svg>
          </button>
        </div>
      </div>

      {/* Mobile Menu */}
      {mobileMenu && (
        <div className="md:hidden bg-white border-t border-gray-100 px-6 py-4 flex flex-col gap-3 animate-fade-in">
          {navLinks.map(({ label, href }) => (
            <a
              key={label}
              href={href}
              className="text-sm font-medium text-gray-600 hover:text-primary-600 py-1.5 transition-colors"
              onClick={() => setMobileMenu(false)}
            >
              {label}
            </a>
          ))}
          {!user && (
            <button
              onClick={() => { setMobileMenu(false); setAuthOpen(true); }}
              className="mt-2 w-full py-2.5 bg-gradient-to-r from-primary-600 to-emerald-500 text-white font-semibold rounded-xl text-sm"
            >
              Register / Sign In
            </button>
          )}
        </div>
      )}
    </nav>
  );
}
